252	void run_sa(const std::vector<std::vector<int>>& init_stacks, int N, int M,
253	            int* best_dests, long long& best_energy) {
254	    std::mt19937 rng(12345);
255	
256	    int current_dests[200];
257	    for (int i = 0; i < N; i++) current_dests[i] = best_dests[i];
258	    long long current_energy = best_energy;
259	
260	    double T_init = 40.0;
261	    double T_final = 0.01;
262	
263	    double sa_start = std::chrono::duration<double>(std::chrono::steady_clock::now() - GLOBAL_START_TIME).count();
264	    double sa_end = TIME_LIMIT_SECONDS;
265	    double sa_duration = sa_end - sa_start;
266	    if (sa_duration < 0.05) return;
267	
268	    SimState base_state, work_state;
269	    base_state.init(N, M, init_stacks);
270	
271	    int next_dests[200];
272	
273	    while (true) {
274	        double now = std::chrono::duration<double>(std::chrono::steady_clock::now() - GLOBAL_START_TIME).count();
275	        if (now >= sa_end) break;
276	        double progress = (now - sa_start) / sa_duration;
277	        if (progress > 1.0) progress = 1.0;
278	        double T = T_init * std::pow(T_final / T_init, progress);
279	
280	        for (int i = 0; i < N; i++) next_dests[i] = current_dests[i];
281	
282	        int op = rng() % 100;
283	        if (op < 45) {
284	            int idx = rng() % N;
285	            next_dests[idx] = rng() % M;
286	        } else if (op < 75) {
287	            int nc = 2 + (rng() % 3);
288	            for (int c = 0; c < nc; c++) {
289	                next_dests[rng() % N] = rng() % M;
290	            }
291	        } else if (op < 90) {
292	            int start = rng() % N;
293	            int len = 2 + (rng() % 8);
294	            for (int i = 0; i < len && start + i < N; i++) {
295	                next_dests[start + i] = rng() % M;
296	            }
297	        } else {
298	            int i1 = rng() % N;
299	            int i2 = rng() % N;
300	            std::swap(next_dests[i1], next_dests[i2]);
301	        }
302	
303	        work_state.copy_from(base_state);
304	        long long next_energy = work_state.evaluate_plan(next_dests);
305	
306	        long long delta = next_energy - current_energy;
307	        if (delta <= 0) {
308	            for (int i = 0; i < N; i++) current_dests[i] = next_dests[i];
309	            current_energy = next_energy;
310	            if (current_energy < best_energy) {
311	                best_energy = current_energy;
312	                for (int i = 0; i < N; i++) best_dests[i] = current_dests[i];
313	            }
314	        } else if (T > 1e-9 && std::uniform_real_distribution<double>(0.0, 1.0)(rng) < std::exp(-(double)delta / T)) {
315	            for (int i = 0; i < N; i++) current_dests[i] = next_dests[i];
316	            current_energy = next_energy;
317	        }
318	    }
319	}
