321	long long reconstruct_single(const std::vector<std::vector<int>>& init_stacks, int N, int M,
322	                             const int* dests, std::vector<std::pair<int, int>>& out_ops) {
323	    State st(N, M, init_stacks);
324	    for (int k = 0; k < N; k++) {
325	        int src = st.box_pos[k].first;
326	        int h = st.box_pos[k].second;
327	        if (h < (int)st.stacks[src].size() - 1) {
328	            int first_above = st.stacks[src][h + 1];
329	            int dest = dests[k];
330	            if (dest == src) dest = (src + 1) % M;
331	            st.move(first_above, dest);
332	        }
333	        st.carry_out(k);
334	    }
335	    out_ops = std::move(st.ops);
336	    return st.energy;
337	}
