const double TIME_LIMIT_SECONDS = 1.92;

struct State {
    std::vector<std::vector<int>> stacks;
    std::vector<std::pair<int, int>> box_pos;
    int N, M;
    long long energy;
    std::vector<std::pair<int, int>> ops;

    State() : N(0), M(0), energy(0) {}

    State(int n, int m, const std::vector<std::vector<int>>& init_stacks)
        : N(n), M(m), energy(0) {
        stacks.resize(M);
        box_pos.resize(N);
        for (int i = 0; i < M; i++) {
            stacks[i] = init_stacks[i];
            for (int j = 0; j < (int)stacks[i].size(); j++) {
                box_pos[stacks[i][j]] = {i, j};
            }
        }
    }

    void move(int box_val, int dest_stack) {
        int src = box_pos[box_val].first;
        int h = box_pos[box_val].second;
        int num_moved = (int)stacks[src].size() - h;

        int dest_sz = (int)stacks[dest_stack].size();
        for (int i = h; i < (int)stacks[src].size(); i++) {
            int bv = stacks[src][i];
            box_pos[bv] = {dest_stack, dest_sz + (i - h)};
        }

        stacks[dest_stack].insert(stacks[dest_stack].end(),
            stacks[src].begin() + h, stacks[src].end());
        stacks[src].erase(stacks[src].begin() + h, stacks[src].end());

        energy += num_moved + 1;
        ops.push_back({box_val + 1, dest_stack + 1});
    }

    void carry_out(int box_val) {
        int src = box_pos[box_val].first;
        stacks[src].pop_back();
        ops.push_back({box_val + 1, 0});
    }
};

// Multi-move: move decreasing suffixes to best destination
long long solve_multi_move(const std::vector<std::vector<int>>& init_stacks, int N, int M,
                           std::vector<std::pair<int, int>>& out_ops) {
    State st(N, M, init_stacks);

    for (int k = 0; k < N; k++) {
        while (true) {
            int src = st.box_pos[k].first;
            int h = st.box_pos[k].second;
            if (h == (int)st.stacks[src].size() - 1) break;

            auto& stk = st.stacks[src];
            int top_idx = (int)stk.size() - 1;

            int group_start = top_idx;
            while (group_start > h + 1 && stk[group_start - 1] > stk[group_start]) {
                group_start--;
            }
            if (group_start <= h) group_start = h + 1;

            int group_bottom_val = stk[group_start];

            double best_score = 1e18;
            int best_dest = (src + 1) % M;

            for (int d = 0; d < M; d++) {
                if (d == src) continue;
                const auto& dstk = st.stacks[d];
                double score = 0.0;

                if (dstk.empty()) {
                    score = 200.0;
                } else {
                    int top = dstk.back();
                    if (top > group_bottom_val) {
                        score = (double)(top - group_bottom_val);
                    } else {
                        score = 5000.0 + (double)dstk.size() * 20.0;
                    }
                    for (int bv : dstk) {
                        if (bv >= k && bv < k + 15) {
                            int urgency = 15 - (bv - k);
                            score += (double)(urgency * urgency) * 2.0;
                        }
                    }
                }
                score += (double)dstk.size() * 0.5;

                if (score < best_score) {
                    best_score = score;
                    best_dest = d;
                }
            }

            st.move(stk[group_start], best_dest);
        }
        st.carry_out(k);
    }

    out_ops = std::move(st.ops);
    return st.energy;
}

// Fast simulation for SA - uses flat arrays
struct SimState {
    int stacks[10][400];
    int stack_size[10];
    int box_stack[200];
    int box_height[200];
    int N, M;

    void init(int n, int m, const std::vector<std::vector<int>>& init_stacks) {
        N = n; M = m;
        for (int i = 0; i < M; i++) {
            stack_size[i] = (int)init_stacks[i].size();
            for (int j = 0; j < stack_size[i]; j++) {
                stacks[i][j] = init_stacks[i][j];
                box_stack[init_stacks[i][j]] = i;
                box_height[init_stacks[i][j]] = j;
            }
        }
    }

    void copy_from(const SimState& o) {
        N = o.N; M = o.M;
        for (int i = 0; i < M; i++) {
            stack_size[i] = o.stack_size[i];
            for (int j = 0; j < stack_size[i]; j++) {
                stacks[i][j] = o.stacks[i][j];
            }
        }
        for (int v = 0; v < N; v++) {
            box_stack[v] = o.box_stack[v];
            box_height[v] = o.box_height[v];
        }
    }

    long long simulate_from(int k_start, const int* dests) {
        long long energy = 0;
        for (int k = k_start; k < 200; k++) {
            int src = box_stack[k];
            int h = box_height[k];
            int ss = stack_size[src];
            if (h < ss - 1) {
                int dest = dests[k];
                if (dest == src) dest = (src + 1) % M;

                int num_moved = ss - h - 1;
                energy += num_moved + 1;

                int ds = stack_size[dest];
                for (int i = h + 1; i < ss; i++) {
                    int bv = stacks[src][i];
                    stacks[dest][ds] = bv;
                    box_stack[bv] = dest;
                    box_height[bv] = ds;
                    ds++;
                }
                stack_size[dest] = ds;
                stack_size[src] = h + 1;
            }
            stack_size[src]--;
        }
        return energy;
    }
};

// Checkpoint-based incremental SA
const int CP_INTERVAL = 10;
const int NUM_CHECKPOINTS = 20; // 200 / 10

struct CheckpointSA {
    SimState checkpoints[NUM_CHECKPOINTS + 1]; // checkpoint[i] = state after processing i*CP_INTERVAL boxes
    long long cumulative_energy[NUM_CHECKPOINTS + 1]; // cumulative_energy[i] = energy for boxes 0..i*CP_INTERVAL-1
    int N, M;
    const std::vector<std::vector<int>>* init_stacks_ptr;

    void build_checkpoints(const int* dests) {
        checkpoints[0].init(N, M, *init_stacks_ptr);
        cumulative_energy[0] = 0;

        for (int cp = 0; cp < NUM_CHECKPOINTS; cp++) {
            checkpoints[cp + 1].copy_from(checkpoints[cp]);
            int start = cp * CP_INTERVAL;
            int end = start + CP_INTERVAL;
            long long seg_energy = 0;
            for (int k = start; k < end; k++) {
                int src = checkpoints[cp + 1].box_stack[k];
                int h = checkpoints[cp + 1].box_height[k];
                int ss = checkpoints[cp + 1].stack_size[src];
                if (h < ss - 1) {
                    int dest = dests[k];
                    if (dest == src) dest = (src + 1) % M;
                    int num_moved = ss - h - 1;
                    seg_energy += num_moved + 1;
                    int ds = checkpoints[cp + 1].stack_size[dest];
                    for (int i = h + 1; i < ss; i++) {
                        int bv = checkpoints[cp + 1].stacks[src][i];
                        checkpoints[cp + 1].stacks[dest][ds] = bv;
                        checkpoints[cp + 1].box_stack[bv] = dest;
                        checkpoints[cp + 1].box_height[bv] = ds;
                        ds++;
                    }
                    checkpoints[cp + 1].stack_size[dest] = ds;
                    checkpoints[cp + 1].stack_size[src] = h + 1;
                }
                checkpoints[cp + 1].stack_size[src]--;
            }
            cumulative_energy[cp + 1] = cumulative_energy[cp] + seg_energy;
        }
    }

    // Evaluate from checkpoint cp_idx to end
    long long evaluate_from_checkpoint(int cp_idx, const int* dests, SimState& work) {
        work.copy_from(checkpoints[cp_idx]);
        long long partial = work.simulate_from(cp_idx * CP_INTERVAL, dests);
        return cumulative_energy[cp_idx] + partial;
    }

    // Rebuild checkpoints from cp_idx onwards (after accepting mutation)
    void rebuild_from(int cp_idx, const int* dests) {
        for (int cp = cp_idx; cp < NUM_CHECKPOINTS; cp++) {
            checkpoints[cp + 1].copy_from(checkpoints[cp]);
            int start = cp * CP_INTERVAL;
            int end = start + CP_INTERVAL;
            long long seg_energy = 0;
            for (int k = start; k < end; k++) {
                int src = checkpoints[cp + 1].box_stack[k];
                int h = checkpoints[cp + 1].box_height[k];
                int ss = checkpoints[cp + 1].stack_size[src];
                if (h < ss - 1) {
                    int dest = dests[k];
                    if (dest == src) dest = (src + 1) % M;
                    int num_moved = ss - h - 1;
                    seg_energy += num_moved + 1;
                    int ds = checkpoints[cp + 1].stack_size[dest];
                    for (int i = h + 1; i < ss; i++) {
                        int bv = checkpoints[cp + 1].stacks[src][i];
                        checkpoints[cp + 1].stacks[dest][ds] = bv;
                        checkpoints[cp + 1].box_stack[bv] = dest;
                        checkpoints[cp + 1].box_height[bv] = ds;
                        ds++;
                    }
                    checkpoints[cp + 1].stack_size[dest] = ds;
                    checkpoints[cp + 1].stack_size[src] = h + 1;
                }
                checkpoints[cp + 1].stack_size[src]--;
            }
            cumulative_energy[cp + 1] = cumulative_energy[cp] + seg_energy;
        }
    }
};

// Generate greedy single-move destinations
void get_greedy_dests(const std::vector<std::vector<int>>& init_stacks, int N, int M, int* dests) {
    SimState ss;
    ss.init(N, M, init_stacks);

    for (int k = 0; k < N; k++) {
        int src = ss.box_stack[k];
        int h = ss.box_height[k];
        int src_size = ss.stack_size[src];

        if (h == src_size - 1) {
            dests[k] = src;
            ss.stack_size[src]--;
            continue;
        }

        double best_score = 1e18;
        int best_dest = (src + 1) % M;

        for (int d = 0; d < M; d++) {
            if (d == src) continue;
            double score = 0.0;
            int ds = ss.stack_size[d];
            if (ds == 0) {
                score = 300.0;
            } else {
                score = (double)ds * 3.0;
                for (int j = 0; j < ds; j++) {
                    int bv = ss.stacks[d][j];
                    if (bv >= k && bv < k + 20) {
                        score += (double)(20 - (bv - k)) * 5.0;
                    }
                }
            }
            if (score < best_score) {
                best_score = score;
                best_dest = d;
            }
        }

        dests[k] = best_dest;

        int dest = best_dest;
        int ds = ss.stack_size[dest];
        for (int i = h + 1; i < src_size; i++) {
            int bv = ss.stacks[src][i];
            ss.stacks[dest][ds] = bv;
            ss.box_stack[bv] = dest;
            ss.box_height[bv] = ds;
            ds++;
        }
        ss.stack_size[dest] = ds;
        ss.stack_size[src] = h + 1;
        ss.stack_size[src]--;
    }
}

// Per-position cost for adaptive mutations
void compute_position_costs(const std::vector<std::vector<int>>& init_stacks, int N, int M,
                           const int* dests, int* costs) {
    SimState ss;
    ss.init(N, M, init_stacks);
    for (int k = 0; k < N; k++) {
        int src = ss.box_stack[k];
        int h = ss.box_height[k];
        int src_size = ss.stack_size[src];
        if (h < src_size - 1) {
            costs[k] = src_size - h; // num_moved + 1
            int dest = dests[k];
            if (dest == src) dest = (src + 1) % M;
            int ds = ss.stack_size[dest];
            for (int i = h + 1; i < src_size; i++) {
                int bv = ss.stacks[src][i];
                ss.stacks[dest][ds] = bv;
                ss.box_stack[bv] = dest;
                ss.box_height[bv] = ds;
                ds++;
            }
            ss.stack_size[dest] = ds;
            ss.stack_size[src] = h + 1;
        } else {
            costs[k] = 0;
        }
        ss.stack_size[src]--;
    }
}

void run_checkpoint_sa(const std::vector<std::vector<int>>& init_stacks, int N, int M,
                       int* best_dests, long long& best_energy) {
    std::mt19937 rng(42);

    int current_dests[200];
    for (int i = 0; i < N; i++) current_dests[i] = best_dests[i];
    long long current_energy = best_energy;

    double T_init = 50.0;
    double T_final = 0.01;

    double sa_start = std::chrono::duration<double>(std::chrono::steady_clock::now() - GLOBAL_START_TIME).count();
    double sa_end = TIME_LIMIT_SECONDS;
    double sa_duration = sa_end - sa_start;
    if (sa_duration < 0.05) return;

    CheckpointSA cpsa;
    cpsa.N = N;
    cpsa.M = M;
    cpsa.init_stacks_ptr = &init_stacks;
    cpsa.build_checkpoints(current_dests);

    SimState work_state;

    // Compute initial position costs for adaptive mutation
    int pos_costs[200];
    compute_position_costs(init_stacks, N, M, current_dests, pos_costs);

    // Build weighted distribution for adaptive mutation
    // Higher cost positions get mutated more often
    double weights[200];
    double total_weight = 0;
    for (int i = 0; i < N; i++) {
        weights[i] = 1.0 + (double)pos_costs[i];
        total_weight += weights[i];
    }

    int iterations = 0;
    int accepts = 0;

    while (true) {
        double now = std::chrono::duration<double>(std::chrono::steady_clock::now() - GLOBAL_START_TIME).count();
        if (now >= sa_end) break;
        double progress = (now - sa_start) / sa_duration;
        if (progress > 1.0) progress = 1.0;
        double T = T_init * std::pow(T_final / T_init, progress);

        // Determine mutation
        int min_mutated_pos = N;
        int next_dests[200];
        for (int i = 0; i < N; i++) next_dests[i] = current_dests[i];

        int op = rng() % 100;
        if (op < 40) {
            // Single adaptive mutation - prefer high-cost positions
            double r = std::uniform_real_distribution<double>(0.0, total_weight)(rng);
            int idx = 0;
            double accum = 0;
            for (int i = 0; i < N; i++) {
                accum += weights[i];
                if (accum >= r) { idx = i; break; }
            }
            next_dests[idx] = rng() % M;
            min_mutated_pos = idx;
        } else if (op < 60) {
            // Single random mutation
            int idx = rng() % N;
            next_dests[idx] = rng() % M;
            min_mutated_pos = idx;
        } else if (op < 80) {
            // Multi-point mutation (2-4 points)
            int nc = 2 + (rng() % 3);
            for (int c = 0; c < nc; c++) {
                int idx = rng() % N;
                next_dests[idx] = rng() % M;
                if (idx < min_mutated_pos) min_mutated_pos = idx;
            }
        } else if (op < 92) {
            // Block mutation
            int start = rng() % N;
            int len = 2 + (rng() % 6);
            for (int i = 0; i < len && start + i < N; i++) {
                next_dests[start + i] = rng() % M;
            }
            min_mutated_pos = start;
        } else {
            // Swap
            int i1 = rng() % N;
            int i2 = rng() % N;
            std::swap(next_dests[i1], next_dests[i2]);
            min_mutated_pos = std::min(i1, i2);
        }

        // Use checkpoint for incremental evaluation
        int cp_idx = min_mutated_pos / CP_INTERVAL;
        long long next_energy = cpsa.evaluate_from_checkpoint(cp_idx, next_dests, work_state);

        long long delta = next_energy - current_energy;
        bool accept = false;
        if (delta <= 0) {
            accept = true;
        } else if (T > 1e-9) {
            double prob = std::exp(-(double)delta / T);
            if (std::uniform_real_distribution<double>(0.0, 1.0)(rng) < prob) {
                accept = true;
            }
        }

        if (accept) {
            for (int i = 0; i < N; i++) current_dests[i] = next_dests[i];
            current_energy = next_energy;
            accepts++;

            // Rebuild checkpoints from mutation point
            cpsa.rebuild_from(cp_idx, current_dests);

            if (current_energy < best_energy) {
                best_energy = current_energy;
                for (int i = 0; i < N; i++) best_dests[i] = current_dests[i];
            }

            // Update position costs periodically
            if (accepts % 50 == 0) {
                compute_position_costs(init_stacks, N, M, current_dests, pos_costs);
                total_weight = 0;
                for (int i = 0; i < N; i++) {
                    weights[i] = 1.0 + (double)pos_costs[i];
                    total_weight += weights[i];
                }
            }
        }

        iterations++;
    }
}

long long reconstruct_single(const std::vector<std::vector<int>>& init_stacks, int N, int M,
