struct State {
    std::vector<std::vector<int>> stacks;
    std::vector<std::pair<int, int>> box_pos;
    int N, M;
    long long energy;
    std::vector<std::pair<int, int>> ops;

    State() : N(0), M(0), energy(0) {}

    State(int n, int m, const std::vector<std::vector<int>>& init_stacks)
        : N(n), M(m), energy(0) {
        stacks.resize(M);
        box_pos.resize(N);
        for (int i = 0; i < M; i++) {
            stacks[i] = init_stacks[i];
            for (int j = 0; j < (int)stacks[i].size(); j++) {
                box_pos[stacks[i][j]] = {i, j};
            }
        }
    }

    void move(int box_val, int dest_stack) {
        int src = box_pos[box_val].first;
        int h = box_pos[box_val].second;
        int num_moved = (int)stacks[src].size() - h;

        int dest_sz = (int)stacks[dest_stack].size();
        for (int i = h; i < (int)stacks[src].size(); i++) {
            int bv = stacks[src][i];
            box_pos[bv] = {dest_stack, dest_sz + (i - h)};
        }

        stacks[dest_stack].insert(stacks[dest_stack].end(),
            stacks[src].begin() + h, stacks[src].end());
        stacks[src].erase(stacks[src].begin() + h, stacks[src].end());

        energy += num_moved + 1;
        ops.push_back({box_val + 1, dest_stack + 1});
    }

    void carry_out(int box_val) {
        int src = box_pos[box_val].first;
        stacks[src].pop_back();
        ops.push_back({box_val + 1, 0});
    }
};

// Multi-move: move decreasing suffixes to best destination
long long solve_multi_move(const std::vector<std::vector<int>>& init_stacks, int N, int M,
                           std::vector<std::pair<int, int>>& out_ops) {
    State st(N, M, init_stacks);

    for (int k = 0; k < N; k++) {
        while (true) {
            int src = st.box_pos[k].first;
            int h = st.box_pos[k].second;
            if (h == (int)st.stacks[src].size() - 1) break;

            auto& stk = st.stacks[src];
            int top_idx = (int)stk.size() - 1;

            int group_start = top_idx;
            while (group_start > h + 1 && stk[group_start - 1] > stk[group_start]) {
                group_start--;
            }
            if (group_start <= h) group_start = h + 1;

            int group_bottom_val = stk[group_start];

            double best_score = 1e18;
            int best_dest = (src + 1) % M;

            for (int d = 0; d < M; d++) {
                if (d == src) continue;
                const auto& dstk = st.stacks[d];
                double score = 0.0;

                if (dstk.empty()) {
                    score = 200.0;
                } else {
                    int top = dstk.back();
                    if (top > group_bottom_val) {
                        score = (double)(top - group_bottom_val);
                    } else {
                        score = 5000.0 + (double)dstk.size() * 20.0;
                    }
                    for (int bv : dstk) {
                        if (bv >= k && bv < k + 15) {
                            int urgency = 15 - (bv - k);
                            score += (double)(urgency * urgency) * 2.0;
                        }
                    }
                }
                score += (double)dstk.size() * 0.5;

                if (score < best_score) {
                    best_score = score;
                    best_dest = d;
                }
            }

            st.move(stk[group_start], best_dest);
        }
        st.carry_out(k);
    }

    out_ops = std::move(st.ops);
    return st.energy;
}

// Fast simulation - flat arrays
struct SimState {
    int stacks[10][400];
    int stack_size[10];
    int box_stack[200];
    int box_height[200];
    int N, M;

    void init(int n, int m, const std::vector<std::vector<int>>& init_stacks) {
        N = n; M = m;
        for (int i = 0; i < M; i++) {
            stack_size[i] = (int)init_stacks[i].size();
            for (int j = 0; j < stack_size[i]; j++) {
                stacks[i][j] = init_stacks[i][j];
                box_stack[init_stacks[i][j]] = i;
                box_height[init_stacks[i][j]] = j;
            }
        }
    }

    void copy_from(const SimState& o) {
        N = o.N; M = o.M;
        memcpy(stack_size, o.stack_size, sizeof(int) * M);
        for (int i = 0; i < M; i++) {
            memcpy(stacks[i], o.stacks[i], sizeof(int) * stack_size[i]);
        }
        memcpy(box_stack, o.box_stack, sizeof(int) * N);
        memcpy(box_height, o.box_height, sizeof(int) * N);
    }

    long long simulate_from(int k_start, const int* dests) {
        long long energy = 0;
        for (int k = k_start; k < 200; k++) {
            int src = box_stack[k];
            int h = box_height[k];
            int ss = stack_size[src];
            if (h < ss - 1) {
                int dest = dests[k];
                if (dest == src) dest = (src + 1) % M;

                int num_moved = ss - h - 1;
                energy += num_moved + 1;

                int ds = stack_size[dest];
                for (int i = h + 1; i < ss; i++) {
                    int bv = stacks[src][i];
                    stacks[dest][ds] = bv;
                    box_stack[bv] = dest;
                    box_height[bv] = ds;
                    ds++;
                }
                stack_size[dest] = ds;
                stack_size[src] = h + 1;
            }
            stack_size[src]--;
        }
        return energy;
    }

    long long evaluate_plan(const int* dests) {
        return simulate_from(0, dests);
    }
};

// Generate greedy single-move destinations
void get_greedy_dests(const std::vector<std::vector<int>>& init_stacks, int N, int M, int* dests) {
    SimState ss;
    ss.init(N, M, init_stacks);

    for (int k = 0; k < N; k++) {
        int src = ss.box_stack[k];
        int h = ss.box_height[k];
        int src_size = ss.stack_size[src];

        if (h == src_size - 1) {
            dests[k] = src;
            ss.stack_size[src]--;
            continue;
        }

        double best_score = 1e18;
        int best_dest = (src + 1) % M;

        for (int d = 0; d < M; d++) {
            if (d == src) continue;
            double score = 0.0;
            int ds = ss.stack_size[d];
            if (ds == 0) {
                score = 300.0;
            } else {
                score = (double)ds * 3.0;
                for (int j = 0; j < ds; j++) {
                    int bv = ss.stacks[d][j];
                    if (bv >= k && bv < k + 20) {
                        score += (double)(20 - (bv - k)) * 5.0;
                    }
                }
            }
            if (score < best_score) {
                best_score = score;
                best_dest = d;
            }
        }

        dests[k] = best_dest;

        int dest = best_dest;
        int ds = ss.stack_size[dest];
        for (int i = h + 1; i < src_size; i++) {
            int bv = ss.stacks[src][i];
            ss.stacks[dest][ds] = bv;
            ss.box_stack[bv] = dest;
            ss.box_height[bv] = ds;
            ds++;
        }
        ss.stack_size[dest] = ds;
        ss.stack_size[src] = h + 1;
        ss.stack_size[src]--;
    }
}

// Segmented SA: divide the 200 positions into segments
// Only resimulate from the first mutated segment onwards
// Keep per-segment energy cache
const int SEG_SIZE = 5;
const int NUM_SEGS = 40; // 200 / 5

struct SegmentedSA {
    SimState seg_states[NUM_SEGS + 1]; // seg_states[i] = state before processing segment i
    long long seg_energy[NUM_SEGS]; // energy of each segment
    long long total_energy;
    int N, M;
    const std::vector<std::vector<int>>* init_stacks_ptr;

    void build_all(const int* dests) {
        seg_states[0].init(N, M, *init_stacks_ptr);
        total_energy = 0;

        for (int s = 0; s < NUM_SEGS; s++) {
            seg_states[s + 1].copy_from(seg_states[s]);
            int start = s * SEG_SIZE;
            int end = start + SEG_SIZE;
            long long e = 0;
            for (int k = start; k < end; k++) {
                int src = seg_states[s + 1].box_stack[k];
                int h = seg_states[s + 1].box_height[k];
                int ss = seg_states[s + 1].stack_size[src];
                if (h < ss - 1) {
                    int dest = dests[k];
                    if (dest == src) dest = (src + 1) % M;
                    int num_moved = ss - h - 1;
                    e += num_moved + 1;
                    int ds = seg_states[s + 1].stack_size[dest];
                    for (int i = h + 1; i < ss; i++) {
                        int bv = seg_states[s + 1].stacks[src][i];
                        seg_states[s + 1].stacks[dest][ds] = bv;
                        seg_states[s + 1].box_stack[bv] = dest;
                        seg_states[s + 1].box_height[bv] = ds;
                        ds++;
                    }
                    seg_states[s + 1].stack_size[dest] = ds;
                    seg_states[s + 1].stack_size[src] = h + 1;
                }
                seg_states[s + 1].stack_size[src]--;
            }
            seg_energy[s] = e;
            total_energy += e;
        }
    }

    // Evaluate with mutation starting at segment seg_idx
    // Returns total energy
    long long evaluate_from_seg(int seg_idx, const int* dests, SimState& work) {
        work.copy_from(seg_states[seg_idx]);
        long long tail_energy = work.simulate_from(seg_idx * SEG_SIZE, dests);
        long long prefix_energy = 0;
        for (int s = 0; s < seg_idx; s++) prefix_energy += seg_energy[s];
        return prefix_energy + tail_energy;
    }

    // Rebuild from segment seg_idx (after accepting)
    void rebuild_from_seg(int seg_idx, const int* dests) {
        total_energy = 0;
        for (int s = 0; s < seg_idx; s++) total_energy += seg_energy[s];

        for (int s = seg_idx; s < NUM_SEGS; s++) {
            seg_states[s + 1].copy_from(seg_states[s]);
            int start = s * SEG_SIZE;
            int end = start + SEG_SIZE;
            long long e = 0;
            for (int k = start; k < end; k++) {
                int src = seg_states[s + 1].box_stack[k];
                int h = seg_states[s + 1].box_height[k];
                int ss = seg_states[s + 1].stack_size[src];
                if (h < ss - 1) {
                    int dest = dests[k];
                    if (dest == src) dest = (src + 1) % M;
                    int num_moved = ss - h - 1;
                    e += num_moved + 1;
                    int ds = seg_states[s + 1].stack_size[dest];
                    for (int i = h + 1; i < ss; i++) {
                        int bv = seg_states[s + 1].stacks[src][i];
                        seg_states[s + 1].stacks[dest][ds] = bv;
                        seg_states[s + 1].box_stack[bv] = dest;
                        seg_states[s + 1].box_height[bv] = ds;
                        ds++;
                    }
                    seg_states[s + 1].stack_size[dest] = ds;
                    seg_states[s + 1].stack_size[src] = h + 1;
                }
                seg_states[s + 1].stack_size[src]--;
            }
            seg_energy[s] = e;
            total_energy += e;
        }
    }
};

void run_segmented_sa(const std::vector<std::vector<int>>& init_stacks, int N, int M,
                      int* best_dests, long long& best_energy) {
    std::mt19937 rng(42);

    int current_dests[200];
    for (int i = 0; i < N; i++) current_dests[i] = best_dests[i];
    long long current_energy = best_energy;

    double T_init = 50.0;
    double T_final = 0.005;

    double sa_start = std::chrono::duration<double>(std::chrono::steady_clock::now() - GLOBAL_START_TIME).count();
    double sa_end = TIME_LIMIT_SECONDS;
    double sa_duration = sa_end - sa_start;
    if (sa_duration < 0.05) return;

    SegmentedSA ssa;
    ssa.N = N;
    ssa.M = M;
    ssa.init_stacks_ptr = &init_stacks;
    ssa.build_all(current_dests);

    SimState work_state;

    while (true) {
        double now = std::chrono::duration<double>(std::chrono::steady_clock::now() - GLOBAL_START_TIME).count();
        if (now >= sa_end) break;
        double progress = (now - sa_start) / sa_duration;
        if (progress > 1.0) progress = 1.0;
        double T = T_init * std::pow(T_final / T_init, progress);

        int min_mutated_pos = N;
        int next_dests[200];
        memcpy(next_dests, current_dests, sizeof(int) * N);

        int op = rng() % 100;
        if (op < 50) {
            // Single mutation
            int idx = rng() % N;
            next_dests[idx] = rng() % M;
            min_mutated_pos = idx;
        } else if (op < 75) {
            // Multi-point (2-4)
            int nc = 2 + (rng() % 3);
            for (int c = 0; c < nc; c++) {
                int idx = rng() % N;
                next_dests[idx] = rng() % M;
                if (idx < min_mutated_pos) min_mutated_pos = idx;
            }
        } else if (op < 90) {
            // Block mutation
            int start = rng() % N;
            int len = 2 + (rng() % 6);
            for (int i = 0; i < len && start + i < N; i++) {
                next_dests[start + i] = rng() % M;
            }
            min_mutated_pos = start;
        } else {
            // Swap
            int i1 = rng() % N;
            int i2 = rng() % N;
            std::swap(next_dests[i1], next_dests[i2]);
            min_mutated_pos = std::min(i1, i2);
        }

        int seg_idx = min_mutated_pos / SEG_SIZE;
        long long next_energy = ssa.evaluate_from_seg(seg_idx, next_dests, work_state);

        long long delta = next_energy - current_energy;
        bool accept = false;
        if (delta <= 0) {
            accept = true;
        } else if (T > 1e-9) {
            double prob = std::exp(-(double)delta / T);
            if (std::uniform_real_distribution<double>(0.0, 1.0)(rng) < prob) {
                accept = true;
            }
        }

        if (accept) {
            memcpy(current_dests, next_dests, sizeof(int) * N);
            current_energy = next_energy;

            // Rebuild segments from mutation point
            ssa.rebuild_from_seg(seg_idx, current_dests);

            if (current_energy < best_energy) {
                best_energy = current_energy;
                memcpy(best_dests, current_dests, sizeof(int) * N);
            }
        }
    }
}

