        int ss = stack_size[src];
        int cost = 0;
        if (h < ss - 1) {
            int actual_dest = dest;
            if (actual_dest == src) actual_dest = (src + 1) % M;
            int num_moved = ss - h - 1;
            cost = num_moved + 1;
            int ds = stack_size[actual_dest];
            for (int i = h + 1; i < ss; i++) {
                int bv = stacks[src][i];
                stacks[actual_dest][ds] = bv;
                box_stack[bv] = actual_dest;
                box_height[bv] = ds;
                ds++;
            }
            stack_size[actual_dest] = ds;
            stack_size[src] = h + 1;
        }
        stack_size[src]--;
        return cost;
    }

    long long simulate_from(int k_start, const int* dests) {
        long long energy = 0;
        for (int k = k_start; k < 200; k++) {
            energy += process_box(k, dests[k]);
        }
        return energy;
    }

    long long evaluate_plan(const int* dests) {
        return simulate_from(0, dests);
    }

    // Heuristic lookahead score for beam search
    // Lower = better
    double heuristic_score(int current_k) {
        double score = 0.0;
        for (int i = 0; i < M; i++) {
            for (int j = 0; j < stack_size[i]; j++) {
                int bv = stacks[i][j];
                if (bv >= current_k) {
                    // Penalty for boxes that are buried (more stuff on top)
                    int depth = stack_size[i] - 1 - j;
                    score += depth * 1.5;
                    // Extra penalty for soon-needed boxes that are buried
                    if (bv < current_k + 20) {
                        int urgency = 20 - (bv - current_k);
                        score += depth * urgency * 0.3;
                    }
                }
            }
        }
        return score;
    }
};

// Beam search: at each step where a move is needed, try all M-1 destinations
// Keep top-B beams based on energy + lookahead heuristic
const int BEAM_WIDTH = 6;

struct BeamEntry {
    SimState state;
    long long energy;
    int dests[200]; // decisions made so far
    double score; // energy + heuristic for ranking
};

long long solve_beam_search(const std::vector<std::vector<int>>& init_stacks, int N, int M,
                            int* out_dests) {
    static BeamEntry beams[2][BEAM_WIDTH];
    int cur = 0, nxt = 1;
    int cur_count = 1;

    beams[cur][0].state.init(N, M, init_stacks);
    beams[cur][0].energy = 0;
    beams[cur][0].score = 0;

    for (int k = 0; k < N; k++) {
        // Check time
        double now = std::chrono::duration<double>(std::chrono::steady_clock::now() - GLOBAL_START_TIME).count();
        if (now > 0.8) {
            // Time pressure: collapse to best beam and go greedy
            int best_b = 0;
            for (int b = 1; b < cur_count; b++) {
                if (beams[cur][b].energy < beams[cur][best_b].energy) best_b = b;
            }
            // Finish greedily
            SimState& st = beams[cur][best_b].state;
            long long energy = beams[cur][best_b].energy;
            for (int kk = k; kk < N; kk++) {
                int src = st.box_stack[kk];
                int h = st.box_height[kk];
                int ss = st.stack_size[src];
                if (h < ss - 1) {
                    // Pick best dest greedily
                    double best_sc = 1e18;
                    int best_d = (src + 1) % M;
                    for (int d = 0; d < M; d++) {
                        if (d == src) continue;
                        double sc = 0.0;
                        int ds = st.stack_size[d];
                        if (ds == 0) sc = 300.0;
                        else {
                            sc = (double)ds * 3.0;
                            for (int j = 0; j < ds; j++) {
                                int bv = st.stacks[d][j];
                                if (bv >= kk && bv < kk + 20) {
                                    sc += (double)(20 - (bv - kk)) * 5.0;
                                }
                            }
                        }
                        if (sc < best_sc) { best_sc = sc; best_d = d; }
                    }
                    beams[cur][best_b].dests[kk] = best_d;
                    energy += st.process_box(kk, best_d);
                } else {
                    beams[cur][best_b].dests[kk] = src;
                    st.stack_size[src]--;
                }
            }
            memcpy(out_dests, beams[cur][best_b].dests, sizeof(int) * N);
            return energy;
        }

        // Check if box k needs moving
        bool any_need_move = false;
        for (int b = 0; b < cur_count; b++) {
            int src = beams[cur][b].state.box_stack[k];
            int h = beams[cur][b].state.box_height[k];
            int ss = beams[cur][b].state.stack_size[src];
            if (h < ss - 1) { any_need_move = true; break; }
        }

        if (!any_need_move) {
            // All beams have k on top - just carry out
            for (int b = 0; b < cur_count; b++) {
                beams[cur][b].dests[k] = beams[cur][b].state.box_stack[k];
                beams[cur][b].state.stack_size[beams[cur][b].state.box_stack[k]]--;
            }
            continue;
        }

        // Expand: for each beam, try all M-1 destinations
        struct Candidate {
            int beam_idx;
            int dest;
            double score;
        };
        static Candidate candidates[BEAM_WIDTH * 10];
        int num_cands = 0;

        for (int b = 0; b < cur_count; b++) {
            int src = beams[cur][b].state.box_stack[k];
            int h = beams[cur][b].state.box_height[k];
            int ss = beams[cur][b].state.stack_size[src];

            if (h == ss - 1) {
                // k is on top, no move needed
                candidates[num_cands++] = {b, src, (double)beams[cur][b].energy};
            } else {
                for (int d = 0; d < M; d++) {
                    if (d == src) continue;
                    // Quick cost estimate
                    int num_moved = ss - h - 1;
                    int cost = num_moved + 1;
                    double new_energy = (double)(beams[cur][b].energy + cost);

                    // Quick heuristic: penalty for covering soon-needed boxes
                    double penalty = 0;
                    int ds = beams[cur][b].state.stack_size[d];
                    for (int i = h + 1; i < ss; i++) {
                        int bv = beams[cur][b].state.stacks[src][i];
                        if (bv < k + 5) penalty += 50.0; // very soon needed
                        else if (bv < k + 15) penalty += 10.0;
                    }
                    // Penalty for burying things in dest
                    for (int j = 0; j < ds; j++) {
                        int bv = beams[cur][b].state.stacks[d][j];
                        if (bv >= k && bv < k + 10) {
                            penalty += (double)(10 - (bv - k)) * 3.0;
                        }
                    }

                    candidates[num_cands++] = {b, d, new_energy + penalty};
                }
            }
        }

        // Sort candidates and pick top BEAM_WIDTH
        std::sort(candidates, candidates + num_cands,
                  [](const Candidate& a, const Candidate& b) { return a.score < b.score; });

        int nxt_count = std::min(num_cands, BEAM_WIDTH);

        for (int i = 0; i < nxt_count; i++) {
            int b = candidates[i].beam_idx;
            int d = candidates[i].dest;
            beams[nxt][i].state.copy_from(beams[cur][b].state);
            beams[nxt][i].energy = beams[cur][b].energy;
            memcpy(beams[nxt][i].dests, beams[cur][b].dests, sizeof(int) * k);
            beams[nxt][i].dests[k] = d;
            beams[nxt][i].energy += beams[nxt][i].state.process_box(k, d);
        }

        std::swap(cur, nxt);
        cur_count = nxt_count;
    }

    // Pick best beam
    int best_b = 0;
    for (int b = 1; b < cur_count; b++) {
        if (beams[cur][b].energy < beams[cur][best_b].energy) best_b = b;
    }
    memcpy(out_dests, beams[cur][best_b].dests, sizeof(int) * N);
    return beams[cur][best_b].energy;
}

// Generate greedy single-move destinations
void get_greedy_dests(const std::vector<std::vector<int>>& init_stacks, int N, int M, int* dests) {
    SimState ss;
    ss.init(N, M, init_stacks);

    for (int k = 0; k < N; k++) {
        int src = ss.box_stack[k];
        int h = ss.box_height[k];
        int src_size = ss.stack_size[src];

        if (h == src_size - 1) {
            dests[k] = src;
            ss.stack_size[src]--;
            continue;
        }

        double best_score = 1e18;
        int best_dest = (src + 1) % M;

        for (int d = 0; d < M; d++) {
            if (d == src) continue;
            double score = 0.0;
            int ds = ss.stack_size[d];
            if (ds == 0) {
                score = 300.0;
            } else {
                score = (double)ds * 3.0;
                for (int j = 0; j < ds; j++) {
                    int bv = ss.stacks[d][j];
                    if (bv >= k && bv < k + 20) {
                        score += (double)(20 - (bv - k)) * 5.0;
                    }
                }
            }
            if (score < best_score) {
                best_score = score;
                best_dest = d;
            }
        }

        dests[k] = best_dest;

        int dest = best_dest;
        int ds = ss.stack_size[dest];
        for (int i = h + 1; i < src_size; i++) {
            int bv = ss.stacks[src][i];
            ss.stacks[dest][ds] = bv;
            ss.box_stack[bv] = dest;
            ss.box_height[bv] = ds;
            ds++;
        }
        ss.stack_size[dest] = ds;
        ss.stack_size[src] = h + 1;
        ss.stack_size[src]--;
    }
}

void run_sa(const std::vector<std::vector<int>>& init_stacks, int N, int M,
            int* best_dests, long long& best_energy) {
    std::mt19937 rng(12345);

    int current_dests[200];
    memcpy(current_dests, best_dests, sizeof(int) * N);
    long long current_energy = best_energy;

    double T_init = 40.0;
    double T_final = 0.01;

    double sa_start = std::chrono::duration<double>(std::chrono::steady_clock::now() - GLOBAL_START_TIME).count();
    double sa_end = TIME_LIMIT_SECONDS;
    double sa_duration = sa_end - sa_start;
    if (sa_duration < 0.05) return;

    SimState base_state, work_state;
    base_state.init(N, M, init_stacks);

    int next_dests[200];

    while (true) {
        double now = std::chrono::duration<double>(std::chrono::steady_clock::now() - GLOBAL_START_TIME).count();
        if (now >= sa_end) break;
        double progress = (now - sa_start) / sa_duration;
        if (progress > 1.0) progress = 1.0;
        double T = T_init * std::pow(T_final / T_init, progress);

        memcpy(next_dests, current_dests, sizeof(int) * N);

        int op = rng() % 100;
        if (op < 45) {
            int idx = rng() % N;
            next_dests[idx] = rng() % M;
        } else if (op < 75) {
            int nc = 2 + (rng() % 3);
            for (int c = 0; c < nc; c++) {
                next_dests[rng() % N] = rng() % M;
            }
        } else if (op < 90) {
            int start = rng() % N;
            int len = 2 + (rng() % 8);
            for (int i = 0; i < len && start + i < N; i++) {
                next_dests[start + i] = rng() % M;
            }
        } else {
            int i1 = rng() % N;
            int i2 = rng() % N;
            std::swap(next_dests[i1], next_dests[i2]);
        }

        work_state.copy_from(base_state);
        long long next_energy = work_state.evaluate_plan(next_dests);

        long long delta = next_energy - current_energy;
        if (delta <= 0) {
            memcpy(current_dests, next_dests, sizeof(int) * N);
            current_energy = next_energy;
            if (current_energy < best_energy) {
                best_energy = current_energy;
                memcpy(best_dests, current_dests, sizeof(int) * N);
            }
        } else if (T > 1e-9 && std::uniform_real_distribution<double>(0.0, 1.0)(rng) < std::exp(-(double)delta / T)) {
            memcpy(current_dests, next_dests, sizeof(int) * N);
            current_energy = next_energy;
        }
    }
}

long long reconstruct_single(const std::vector<std::vector<int>>& init_stacks, int N, int M,
                             const int* dests, std::vector<std::pair<int, int>>& out_ops) {
    State st(N, M, init_stacks);
    for (int k = 0; k < N; k++) {
        int src = st.box_pos[k].first;
        int h = st.box_pos[k].second;
        if (h < (int)st.stacks[src].size() - 1) {
            int first_above = st.stacks[src][h + 1];
            int dest = dests[k];
            if (dest == src) dest = (src + 1) % M;
            st.move(first_above, dest);
        }
        st.carry_out(k);
    }
    out_ops = std::move(st.ops);
    return st.energy;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    GLOBAL_START_TIME = std::chrono::steady_clock::now();

    int N, M;
    std::cin >> N >> M;

    std::vector<std::vector<int>> init_stacks(M);
    for (int i = 0; i < M; i++) {
        init_stacks[i].resize(N / M);
        for (int j = 0; j < N / M; j++) {
            std::cin >> init_stacks[i][j];
            init_stacks[i][j]--;
        }
    }

    // Approach 1: Multi-move with patience-sort
    std::vector<std::pair<int, int>> multi_ops;
    long long multi_energy = solve_multi_move(init_stacks, N, M, multi_ops);

    // Approach 2: Beam search to get initial plan, then SA
    int beam_dests[200];
    long long beam_energy = solve_beam_search(init_stacks, N, M, beam_dests);

    // Also get greedy dests
    int greedy_dests[200];
    get_greedy_dests(init_stacks, N, M, greedy_dests);
    SimState eval_state;
    eval_state.init(N, M, init_stacks);
    long long greedy_energy = eval_state.evaluate_plan(greedy_dests);

    // Start SA from the better of beam and greedy
    int sa_dests[200];
    long long sa_energy;
    if (beam_energy < greedy_energy) {
        memcpy(sa_dests, beam_dests, sizeof(int) * N);
        sa_energy = beam_energy;
    } else {
        memcpy(sa_dests, greedy_dests, sizeof(int) * N);
        sa_energy = greedy_energy;
    }

    run_sa(init_stacks, N, M, sa_dests, sa_energy);

    // Pick best of multi-move and SA
    long long best_energy;
    std::vector<std::pair<int, int>> best_ops;

    if (multi_energy <= sa_energy && (int)multi_ops.size() <= 5000) {
        best_energy = multi_energy;
        best_ops = multi_ops;
    } else {
        std::vector<std::pair<int, int>> sa_ops;
        reconstruct_single(init_stacks, N, M, sa_dests, sa_ops);
        if ((int)sa_ops.size() <= 5000) {
            best_energy = sa_energy;
            best_ops = sa_ops;
        } else {
            best_energy = multi_energy;
            best_ops = multi_ops;
        }
    }

    for (auto& op : best_ops) {
        std::cout << op.first << " " << op.second << "\n";
    }

    return 0;
}
