#include <cstring>

auto GLOBAL_START_TIME = std::chrono::steady_clock::now();
const double TIME_LIMIT_SECONDS = 1.92;

struct State {
    std::vector<std::vector<int>> stacks;
    std::vector<std::pair<int, int>> box_pos;
    int N, M;
    long long energy;
    std::vector<std::pair<int, int>> ops;

    State() : N(0), M(0), energy(0) {}

    State(int n, int m, const std::vector<std::vector<int>>& init_stacks)
        : N(n), M(m), energy(0) {
        stacks.resize(M);
        box_pos.resize(N);
        for (int i = 0; i < M; i++) {
            stacks[i] = init_stacks[i];
            for (int j = 0; j < (int)stacks[i].size(); j++) {
                box_pos[stacks[i][j]] = {i, j};
            }
        }
    }

    void move(int box_val, int dest_stack) {
        int src = box_pos[box_val].first;
        int h = box_pos[box_val].second;
        int num_moved = (int)stacks[src].size() - h;

        int dest_sz = (int)stacks[dest_stack].size();
        for (int i = h; i < (int)stacks[src].size(); i++) {
            int bv = stacks[src][i];
            box_pos[bv] = {dest_stack, dest_sz + (i - h)};
        }

        stacks[dest_stack].insert(stacks[dest_stack].end(),
            stacks[src].begin() + h, stacks[src].end());
        stacks[src].erase(stacks[src].begin() + h, stacks[src].end());

        energy += num_moved + 1;
        ops.push_back({box_val + 1, dest_stack + 1});
    }

    void carry_out(int box_val) {
        int src = box_pos[box_val].first;
        stacks[src].pop_back();
        ops.push_back({box_val + 1, 0});
    }
};

// Multi-move: move decreasing suffixes to best destination
long long solve_multi_move(const std::vector<std::vector<int>>& init_stacks, int N, int M,
                           std::vector<std::pair<int, int>>& out_ops) {
    State st(N, M, init_stacks);

    for (int k = 0; k < N; k++) {
        while (true) {
            int src = st.box_pos[k].first;
            int h = st.box_pos[k].second;
            if (h == (int)st.stacks[src].size() - 1) break;

            auto& stk = st.stacks[src];
            int top_idx = (int)stk.size() - 1;

            int group_start = top_idx;
            while (group_start > h + 1 && stk[group_start - 1] > stk[group_start]) {
                group_start--;
            }
            if (group_start <= h) group_start = h + 1;

            int group_bottom_val = stk[group_start];

            double best_score = 1e18;
            int best_dest = (src + 1) % M;

            for (int d = 0; d < M; d++) {
                if (d == src) continue;
                const auto& dstk = st.stacks[d];
                double score = 0.0;

                if (dstk.empty()) {
                    score = 200.0;
                } else {
                    int top = dstk.back();
                    if (top > group_bottom_val) {
                        score = (double)(top - group_bottom_val);
                    } else {
                        score = 5000.0 + (double)dstk.size() * 20.0;
                    }
                    for (int bv : dstk) {
                        if (bv >= k && bv < k + 15) {
                            int urgency = 15 - (bv - k);
                            score += (double)(urgency * urgency) * 2.0;
                        }
                    }
                }
                score += (double)dstk.size() * 0.5;

                if (score < best_score) {
                    best_score = score;
                    best_dest = d;
                }
            }

            st.move(stk[group_start], best_dest);
        }
        st.carry_out(k);
    }

    out_ops = std::move(st.ops);
    return st.energy;
}

// Fast simulation for SA - flat arrays
struct SimState {
    int stacks[10][400];
    int stack_size[10];
    int box_stack[200];
    int box_height[200];
    int N, M;

    void init(int n, int m, const std::vector<std::vector<int>>& init_stacks) {
        N = n; M = m;
        for (int i = 0; i < M; i++) {
            stack_size[i] = (int)init_stacks[i].size();
            for (int j = 0; j < stack_size[i]; j++) {
                stacks[i][j] = init_stacks[i][j];
                box_stack[init_stacks[i][j]] = i;
                box_height[init_stacks[i][j]] = j;
            }
        }
    }

    void copy_from(const SimState& o) {
        N = o.N; M = o.M;
        memcpy(stack_size, o.stack_size, sizeof(int) * M);
        for (int i = 0; i < M; i++) {
            memcpy(stacks[i], o.stacks[i], sizeof(int) * stack_size[i]);
        }
        memcpy(box_stack, o.box_stack, sizeof(int) * N);
        memcpy(box_height, o.box_height, sizeof(int) * N);
    }

    long long simulate_from(int k_start, const int* dests) {
        long long energy = 0;
        for (int k = k_start; k < 200; k++) {
            int src = box_stack[k];
            int h = box_height[k];
            int ss = stack_size[src];
            if (h < ss - 1) {
                int dest = dests[k];
                if (dest == src) dest = (src + 1) % M;
                int num_moved = ss - h - 1;
                energy += num_moved + 1;
                int ds = stack_size[dest];
                for (int i = h + 1; i < ss; i++) {
                    int bv = stacks[src][i];
                    stacks[dest][ds] = bv;
                    box_stack[bv] = dest;
                    box_height[bv] = ds;
                    ds++;
                }
                stack_size[dest] = ds;
                stack_size[src] = h + 1;
            }
            stack_size[src]--;
        }
        return energy;
    }

    long long evaluate_plan(const int* dests) {
        return simulate_from(0, dests);
    }
};

// Checkpoint-based incremental SA
const int CP_INTERVAL = 10;
const int NUM_CHECKPOINTS = 20; // 200 / 10

struct CheckpointSA {
    SimState checkpoints[NUM_CHECKPOINTS + 1];
    long long cumulative_energy[NUM_CHECKPOINTS + 1];
    int N, M;
    const std::vector<std::vector<int>>* init_stacks_ptr;

    void simulate_segment(SimState& st, int start, int end, const int* dests, long long& seg_energy) {
        seg_energy = 0;
        for (int k = start; k < end; k++) {
            int src = st.box_stack[k];
            int h = st.box_height[k];
            int ss = st.stack_size[src];
            if (h < ss - 1) {
