311	    int current_dests[200];
312	    memcpy(current_dests, best_dests, sizeof(int) * N);
313	    long long current_energy = best_energy;
314	
315	    double T_init = 50.0;
316	    double T_final = 0.01;
317	
318	    double sa_start = std::chrono::duration<double>(std::chrono::steady_clock::now() - GLOBAL_START_TIME).count();
319	    double sa_end = TIME_LIMIT_SECONDS;
320	    double sa_duration = sa_end - sa_start;
321	    if (sa_duration < 0.05) return;
322	
323	    CheckpointSA cpsa;
324	    cpsa.N = N;
325	    cpsa.M = M;
326	    cpsa.init_stacks_ptr = &init_stacks;
327	    cpsa.build_checkpoints(current_dests);
328	
329	    SimState work_state;
330	    int next_dests[200];
331	
332	    while (true) {
333	        double now = std::chrono::duration<double>(std::chrono::steady_clock::now() - GLOBAL_START_TIME).count();
334	        if (now >= sa_end) break;
335	        double progress = (now - sa_start) / sa_duration;
336	        if (progress > 1.0) progress = 1.0;
337	        double T = T_init * std::pow(T_final / T_init, progress);
338	
339	        memcpy(next_dests, current_dests, sizeof(int) * N);
340	
341	        int min_mutated_pos = N;
342	        int op = rng() % 100;
343	        if (op < 50) {
344	            int idx = rng() % N;
345	            next_dests[idx] = rng() % M;
346	            min_mutated_pos = idx;
347	        } else if (op < 75) {
348	            int nc = 2 + (rng() % 3);
349	            for (int c = 0; c < nc; c++) {
350	                int idx = rng() % N;
351	                next_dests[idx] = rng() % M;
352	                if (idx < min_mutated_pos) min_mutated_pos = idx;
353	            }
354	        } else if (op < 90) {
355	            int start = rng() % N;
356	            int len = 2 + (rng() % 6);
357	            for (int i = 0; i < len && start + i < N; i++) {
358	                next_dests[start + i] = rng() % M;
359	            }
360	            min_mutated_pos = start;
361	        } else {
362	            int i1 = rng() % N;
363	            int i2 = rng() % N;
364	            std::swap(next_dests[i1], next_dests[i2]);
365	            min_mutated_pos = std::min(i1, i2);
366	        }
367	
368	        int cp_idx = min_mutated_pos / CP_INTERVAL;
369	        long long next_energy = cpsa.evaluate_from_checkpoint(cp_idx, next_dests, work_state);
370	
371	        long long delta = next_energy - current_energy;
372	        bool accept = false;
373	        if (delta <= 0) {
374	            accept = true;
375	        } else if (T > 1e-9) {
376	            double prob = std::exp(-(double)delta / T);
377	            if (std::uniform_real_distribution<double>(0.0, 1.0)(rng) < prob) {
378	                accept = true;
379	            }
380	        }
381	
382	        if (accept) {
383	            memcpy(current_dests, next_dests, sizeof(int) * N);
384	            current_energy = next_energy;
385	            cpsa.rebuild_from(cp_idx, current_dests);
386	            if (current_energy < best_energy) {
387	                best_energy = current_energy;
388	                memcpy(best_dests, current_dests, sizeof(int) * N);
389	            }
390	        }
391	    }
