63	long long solve_multi_move(const std::vector<std::vector<int>>& init_stacks, int N, int M,
64	                           std::vector<std::pair<int, int>>& out_ops) {
65	    State st(N, M, init_stacks);
66	
67	    for (int k = 0; k < N; k++) {
68	        while (true) {
69	            int src = st.box_pos[k].first;
70	            int h = st.box_pos[k].second;
71	            if (h == (int)st.stacks[src].size() - 1) break;
72	
73	            auto& stk = st.stacks[src];
74	            int top_idx = (int)stk.size() - 1;
75	
76	            int group_start = top_idx;
77	            while (group_start > h + 1 && stk[group_start - 1] > stk[group_start]) {
78	                group_start--;
79	            }
80	            if (group_start <= h) group_start = h + 1;
81	
82	            int group_bottom_val = stk[group_start];
83	
84	            double best_score = 1e18;
85	            int best_dest = (src + 1) % M;
86	
87	            for (int d = 0; d < M; d++) {
88	                if (d == src) continue;
89	                const auto& dstk = st.stacks[d];
90	                double score = 0.0;
91	
92	                if (dstk.empty()) {
93	                    score = 200.0;
94	                } else {
95	                    int top = dstk.back();
96	                    if (top > group_bottom_val) {
97	                        score = (double)(top - group_bottom_val);
98	                    } else {
99	                        score = 5000.0 + (double)dstk.size() * 20.0;
100	                    }
101	                    for (int bv : dstk) {
102	                        if (bv >= k && bv < k + 15) {
103	                            int urgency = 15 - (bv - k);
104	                            score += (double)(urgency * urgency) * 2.0;
105	                        }
106	                    }
107	                }
108	                score += (double)dstk.size() * 0.5;
109	
110	                if (score < best_score) {
111	                    best_score = score;
112	                    best_dest = d;
113	                }
114	            }
115	
116	            st.move(stk[group_start], best_dest);
117	        }
118	        st.carry_out(k);
119	    }
