void run_checkpoint_sa(const std::vector<std::vector<int>>& init_stacks, int N, int M,
                       int* best_dests, long long& best_energy) {
    std::mt19937 rng(42);

    int current_dests[200];
    memcpy(current_dests, best_dests, sizeof(int) * N);
    long long current_energy = best_energy;

    double T_init = 40.0;
    double T_final = 0.1;

    double sa_start = std::chrono::duration<double>(std::chrono::steady_clock::now() - GLOBAL_START_TIME).count();
    double sa_end = TIME_LIMIT_SECONDS;
    double sa_duration = sa_end - sa_start;
    if (sa_duration < 0.05) return;

    CheckpointSA cpsa;
    cpsa.N = N;
    cpsa.M = M;
    cpsa.init_stacks_ptr = &init_stacks;
    cpsa.build_checkpoints(current_dests);

    SimState work_state;
    int next_dests[200];

    int no_improve_count = 0;
    long long last_best = best_energy;

    while (true) {
        double now = std::chrono::duration<double>(std::chrono::steady_clock::now() - GLOBAL_START_TIME).count();
        if (now >= sa_end) break;
        double progress = (now - sa_start) / sa_duration;
        if (progress > 1.0) progress = 1.0;
        double T = T_init * std::pow(T_final / T_init, progress);

        memcpy(next_dests, current_dests, sizeof(int) * N);

        int min_mutated_pos = N;
        int op = rng() % 100;
        if (op < 50) {
            int idx = rng() % N;
            next_dests[idx] = rng() % M;
            min_mutated_pos = idx;
        } else if (op < 75) {
            int nc = 2 + (rng() % 3);
            for (int c = 0; c < nc; c++) {
                int idx = rng() % N;
                next_dests[idx] = rng() % M;
                if (idx < min_mutated_pos) min_mutated_pos = idx;
            }
        } else if (op < 90) {
            int start = rng() % N;
            int len = 2 + (rng() % 6);
            for (int i = 0; i < len && start + i < N; i++) {
                next_dests[start + i] = rng() % M;
            }
            min_mutated_pos = start;
        } else {
            int i1 = rng() % N;
            int i2 = rng() % N;
            std::swap(next_dests[i1], next_dests[i2]);
            min_mutated_pos = std::min(i1, i2);
        }

        int cp_idx = min_mutated_pos / CP_INTERVAL;
        long long next_energy = cpsa.evaluate_from_checkpoint(cp_idx, next_dests, work_state);

        long long delta = next_energy - current_energy;
        bool accept = false;
        if (delta <= 0) {
            accept = true;
        } else if (T > 1e-9) {
            double prob = std::exp(-(double)delta / T);
            if (std::uniform_real_distribution<double>(0.0, 1.0)(rng) < prob) {
                accept = true;
            }
        }

        if (accept) {
            memcpy(current_dests, next_dests, sizeof(int) * N);
            current_energy = next_energy;
            cpsa.rebuild_from(cp_idx, current_dests);
            if (current_energy < best_energy) {
                best_energy = current_energy;
                memcpy(best_dests, current_dests, sizeof(int) * N);
                no_improve_count = 0;
                last_best = best_energy;
            }
        }

        no_improve_count++;
        // Restart from best if stuck
        if (no_improve_count > 2000 && progress < 0.85) {
            memcpy(current_dests, best_dests, sizeof(int) * N);
            current_energy = best_energy;
            cpsa.build_checkpoints(current_dests);
            no_improve_count = 0;
        }
    }

