    for (int k = 0; k < N; k++) {
        int src = ss.box_stack[k];
        int h = ss.box_height[k];
        int src_size = ss.stack_size[src];

        if (h == src_size - 1) {
            dests[k] = src;
            ss.stack_size[src]--;
            continue;
        }

        // Find min value being moved (first one above k that will need to come out)
        int min_moved = 999;
        for (int i = h + 1; i < src_size; i++) {
            if (ss.stacks[src][i] < min_moved) min_moved = ss.stacks[src][i];
        }

        double best_score = 1e18;
        int best_dest = (src + 1) % M;

        for (int d = 0; d < M; d++) {
            if (d == src) continue;
            double score = 0.0;
            int ds = ss.stack_size[d];
            if (ds == 0) {
                score = 200.0;
            } else {
                int top_val = ss.stacks[d][ds - 1];
                // Prefer placing on stacks where top > min_moved (sorted order)
                if (top_val > min_moved) {
                    score = (double)(top_val - min_moved) * 0.5;
                } else {
                    score = 500.0 + (double)(min_moved - top_val) * 2.0;
                }
                score += (double)ds * 2.0;
                for (int j = 0; j < ds; j++) {
                    int bv = ss.stacks[d][j];
                    if (bv >= k && bv < k + 20) {
