            if (current_energy < best_energy) {
                best_energy = current_energy;
                memcpy(best_dests, current_dests, sizeof(int) * N);
            }
        }
    }
}

long long reconstruct_single(const std::vector<std::vector<int>>& init_stacks, int N, int M,
                             const int* dests, std::vector<std::pair<int, int>>& out_ops) {
    State st(N, M, init_stacks);
